export async function seedWebCheck() {
    try {
        console.log("Seeding tool Web-Check...");
        await Tool.deleteMany({ name: "Web-Check" });
        
        const toolDoc = new Tool(toolPayload);
        await toolDoc.save();
        
        console.log("Seeded tool Web-Check successfully.");
    } catch (error) {
        console.error("Seeding tool Web-Check failed:", error);
        throw error;
    }
}
